document.querySelectorAll("div.metadata").forEach(e=>{e.removeAttribute("class")});document.querySelectorAll("header, footer").forEach(e=>e.remove());document.querySelectorAll(".richtext").forEach(e=>{e.classList.remove("richtext"),e.classList.length||e.removeAttribute("class")});const c=["/fragments/","/schedules/","youtube.com","youtu.be"];document.querySelectorAll("a[href]").forEach(e=>{const t=e.getAttribute("href");c.some(r=>t.includes(r))&&(e.setAttribute("data-ue-href",t),e.setAttribute("href","#"))});document.querySelectorAll("picture").forEach(e=>{if(!e.querySelector("source")){const t=e.querySelector("img");if(t){const r=document.createElement("source");r.setAttribute("srcset",t.src),e.prepend(r)}}});
